import React, { useState } from "react";
import { ethers } from "ethers";
// Ensure these paths match your folder structure
import CrowdfundingABI from "../utils/abi/Crowdfunding.json";
import addresses from "../utils/addresses.json";

export default function Refund() {
  const [campaignId, setCampaignId] = useState("");
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ type: "", text: "" });

  const handleRefund = async (e) => {
    e.preventDefault();
    setMessage({ type: "", text: "" });

    if (!window.ethereum) {
      setMessage({ type: "error", text: "Please install MetaMask to use this feature." });
      return;
    }

    try {
      setLoading(true);
      
      const provider = new ethers.BrowserProvider(window.ethereum);
      const signer = await provider.getSigner();
      
      const contract = new ethers.Contract(
        addresses.Crowdfunding, 
        CrowdfundingABI.abi, 
        signer
      );

      const tx = await contract.claimRefund(campaignId);
      setMessage({ type: "info", text: "Processing refund... please wait." });
      
      await tx.wait();
      setMessage({ type: "success", text: `Success! Refund claimed for Campaign ${campaignId}.` });
      setCampaignId("");

    } catch (error) {
      console.error(error);
      const errorMsg = error.reason || error.message || "Transaction failed.";
      setMessage({ type: "error", text: errorMsg });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ fontFamily: "sans-serif", padding: "40px", color: "#111827", maxWidth: "800px" }}>
      {/* Header Section */}
      <h1 style={{ fontSize: "32px", fontWeight: "bold", margin: "0 0 8px 0" }}>
        Refunds
      </h1>
      <p style={{ color: "#6b7280", fontSize: "16px", margin: "0 0 32px 0" }}>
        Get your ETH back if a campaign failed.
      </p>

      {/* Main Card */}
      <div style={{ 
        backgroundColor: "#ffffff", 
        border: "1px solid #e5e7eb", 
        borderRadius: "8px", 
        padding: "24px", 
        maxWidth: "400px",
        boxShadow: "0 1px 3px rgba(0,0,0,0.05)"
      }}>
        <h2 style={{ fontSize: "18px", fontWeight: "600", margin: "0 0 20px 0" }}>
          Claim Your Refund
        </h2>
        
        <form onSubmit={handleRefund}>
          <div style={{ marginBottom: "20px" }}>
            <label style={{ 
              display: "block", 
              fontSize: "14px", 
              fontWeight: "500", 
              marginBottom: "8px",
              color: "#374151"
            }}>
              Campaign ID
            </label>
            <input
              type="number"
              placeholder="e.g. 1"
              value={campaignId}
              onChange={(e) => setCampaignId(e.target.value)}
              required
              style={{ 
                width: "100%", 
                padding: "10px 12px", 
                fontSize: "14px",
                border: "1px solid #d1d5db",
                borderRadius: "6px",
                boxSizing: "border-box",
                outline: "none"
              }}
            />
          </div>
          
          <button 
            type="submit" 
            disabled={loading || !campaignId}
            style={{ 
              width: "100%",
              padding: "10px", 
              fontSize: "14px", 
              fontWeight: "500",
              backgroundColor: loading ? "#9ca3af" : "#000000",
              color: "#ffffff",
              border: "none",
              borderRadius: "6px",
              cursor: loading ? "not-allowed" : "pointer",
              transition: "background-color 0.2s"
            }}
          >
            {loading ? "Processing..." : "Claim Refund"}
          </button>
        </form>

        {/* Status Messages */}
        {message.text && (
          <div style={{ 
            marginTop: "20px", 
            padding: "12px", 
            borderRadius: "6px", 
            fontSize: "14px",
            backgroundColor: message.type === "error" ? "#fee2e2" : message.type === "success" ? "#dcfce3" : "#f3f4f6",
            color: message.type === "error" ? "#991b1b" : message.type === "success" ? "#166534" : "#1f2937",
            border: `1px solid ${message.type === "error" ? "#f87171" : message.type === "success" ? "#86efac" : "#d1d5db"}`
          }}>
            {message.text}
          </div>
        )}
      </div>
    </div>
  );
}
